function apca(bgColor, fgColor) {
  const bgRgb = asRgb(bgColor);
  const fgRgb = asRgb(fgColor);
  const normBG = 0.56;
  const normTXT = 0.57;
  const revTXT = 0.62;
  const revBG = 0.65;
  const blkThrs = 0.022;
  const blkClmp = 1.414;
  const loClip = 0.1;
  const deltaYmin = 5e-4;
  const scaleBoW = 1.14;
  const loBoWoffset = 0.027;
  const scaleWoB = 1.14;
  const loWoBoffset = 0.027;
  function fclamp(Y) {
    return Y >= blkThrs ? Y : Y + (blkThrs - Y) ** blkClmp;
  }
  function linearize(val) {
    const sign = val < 0 ? -1 : 1;
    return sign * Math.pow(Math.abs(val), 2.4);
  }
  const Yfg = fclamp(
    linearize(fgRgb.r / 255) * 0.2126729 + linearize(fgRgb.g / 255) * 0.7151522 + linearize(fgRgb.b / 255) * 0.072175
  );
  const Ybg = fclamp(
    linearize(bgRgb.r / 255) * 0.2126729 + linearize(bgRgb.g / 255) * 0.7151522 + linearize(bgRgb.b / 255) * 0.072175
  );
  let S, C;
  if (Math.abs(Ybg - Yfg) < deltaYmin) C = 0;
  else {
    if (Ybg > Yfg) {
      S = Ybg ** normBG - Yfg ** normTXT;
      C = S * scaleBoW;
    } else {
      S = Ybg ** revBG - Yfg ** revTXT;
      C = S * scaleWoB;
    }
  }
  if (Math.abs(C) < loClip) return 0;
  if (C > 0) return C - loWoBoffset;
  return C + loBoWoffset;
}
function contrastingColor(arg) {
  let bg, fg1, fg2;
  if (typeof arg !== "object" || !("bg" in arg)) {
    bg = asRgb(arg);
    fg1 = "#ffffff";
    fg2 = "#000000";
  } else {
    bg = arg.bg;
    fg1 = arg.fg1;
    fg2 = arg.fg2;
  }
  const contrast1 = Math.abs(apca(fg1, bg));
  const contrast2 = Math.abs(apca(fg2, bg));
  return contrast1 >= contrast2 ? asColorNumber(fg1) : asColorNumber(fg2);
}

